Q: Write a C++ program that calculates the value of a*b, where a and b are two positive integers given by the user.

A: ```cpp
#include <iostream>
using namespace std;

int main() {
    int a, b;
    cout << "Enter the value of a: ";
    cin >> a;
    cout << "Enter the value of b: ";
    cin >> b;
    int result = a * b;
    cout << "The value of " << a << "*" << b << " = " << result << endl;
    return 0;
}
```

